import { useState } from 'react';
import { Header } from './components/Header';
import { InputsPanel } from './components/InputsPanel';
import { ScenarioOverview } from './components/tabs/ScenarioOverview';
import { PhilanthropicProjection } from './components/tabs/PhilanthropicProjection';
import { EndowmentRunway } from './components/tabs/EndowmentRunway';
import { SensitivityTornado } from './components/tabs/SensitivityTornado';
import { MonteCarloStress } from './components/tabs/MonteCarloStress';
import { DEFAULT_INPUTS } from './lib/model';
import type { FinancialInputs } from './lib/model';

type TabKey = 'scenarios' | 'philanthropic' | 'runway' | 'sensitivity' | 'monteCarlo';

const TABS: { key: TabKey; label: string; sub: string }[] = [
  { key: 'scenarios', label: 'Scenario Overview', sub: 'Base · Optimistic · Pessimistic' },
  { key: 'philanthropic', label: 'Philanthropic Revenue', sub: 'Committed · Likely · Gap' },
  { key: 'runway', label: 'Endowment Runway', sub: 'Spend rate guardrails' },
  { key: 'sensitivity', label: 'Sensitivity', sub: 'Tornado of input drivers' },
  { key: 'monteCarlo', label: 'Stress Test', sub: 'Monte Carlo distribution' },
];

export default function App() {
  const [inputs, setInputs] = useState<FinancialInputs>(DEFAULT_INPUTS);
  const [tab, setTab] = useState<TabKey>('scenarios');

  const today = new Date().toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });

  return (
    <div className="min-h-screen flex flex-col">
      <Header asOf={today} />

      <nav className="bg-white border-b border-navy/10 no-print">
        <div className="max-w-screen-2xl mx-auto px-6">
          <div className="flex gap-1 overflow-x-auto -mb-px">
            {TABS.map((t) => (
              <button
                key={t.key}
                onClick={() => setTab(t.key)}
                className={`px-4 py-3 text-left border-b-2 transition-colors whitespace-nowrap ${
                  tab === t.key
                    ? 'border-purple text-navy'
                    : 'border-transparent text-navy/60 hover:text-navy hover:border-navy/30'
                }`}
              >
                <div className="font-head uppercase tracking-wide-15 text-sm">{t.label}</div>
                <div className="text-[11px] text-navy/50 font-sub">{t.sub}</div>
              </button>
            ))}
          </div>
        </div>
      </nav>

      <main className="flex-1 bg-tan/40">
        <div className="max-w-screen-2xl mx-auto px-6 py-6 grid grid-cols-1 lg:grid-cols-[20rem_1fr] gap-6">
          <InputsPanel inputs={inputs} setInputs={setInputs} />
          <div>
            {tab === 'scenarios' && <ScenarioOverview inputs={inputs} />}
            {tab === 'philanthropic' && (
              <PhilanthropicProjection inputs={inputs} setInputs={setInputs} />
            )}
            {tab === 'runway' && <EndowmentRunway inputs={inputs} />}
            {tab === 'sensitivity' && <SensitivityTornado inputs={inputs} />}
            {tab === 'monteCarlo' && <MonteCarloStress inputs={inputs} />}
          </div>
        </div>
      </main>

      <footer className="bg-navy text-white/70 text-xs no-print">
        <div className="max-w-screen-2xl mx-auto px-6 py-4 flex items-center justify-between flex-wrap gap-2">
          <div>DC CAP Innovation Hub · Financial Scenarios · v0.1</div>
          <div className="font-head uppercase tracking-wide-15 text-purple-100">
            Excel Beyond Belief
          </div>
        </div>
      </footer>
    </div>
  );
}
