import { useMemo, useState } from 'react';
import {
  CartesianGrid,
  Legend,
  Line,
  LineChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { FinancialInputs, ScenarioName } from '../../lib/model';
import { HISTORICAL_ENDOWMENT, projectAllScenarios } from '../../lib/model';
import { dollars, fyLabel, millions } from '../../lib/format';
import { SCENARIO_COLORS } from '../../lib/colors';

interface Props {
  inputs: FinancialInputs;
}

export function ScenarioOverview({ inputs }: Props) {
  const [scenario, setScenario] = useState<ScenarioName>('Base');

  const scenarios = useMemo(() => projectAllScenarios(inputs), [inputs]);
  const active = scenarios.find((s) => s.scenario === scenario)!;

  // Build chart data: historical + 3 scenarios
  const chartData = useMemo(() => {
    const map = new Map<number, Record<string, number | null>>();
    HISTORICAL_ENDOWMENT.forEach(({ fiscalYear, endingEndowment }) => {
      map.set(fiscalYear, { Historical: endingEndowment });
    });
    scenarios.forEach((s) => {
      s.years.forEach((y) => {
        const row = map.get(y.fiscalYear) ?? {};
        row[s.scenario] = y.endingEndowment;
        map.set(y.fiscalYear, row);
      });
    });
    // Bridge: include FY26 historical endpoint as the start of all scenario lines
    const lastHist = HISTORICAL_ENDOWMENT[HISTORICAL_ENDOWMENT.length - 1];
    const bridge = map.get(lastHist.fiscalYear) ?? {};
    bridge.Base = lastHist.endingEndowment;
    bridge.Optimistic = lastHist.endingEndowment;
    bridge.Pessimistic = lastHist.endingEndowment;
    map.set(lastHist.fiscalYear, bridge);

    return Array.from(map.entries())
      .sort(([a], [b]) => a - b)
      .map(([fiscalYear, vals]) => ({ fiscalYear, ...vals }));
  }, [scenarios]);

  const rowDefs = [
    { key: 'fundraising', label: 'Fundraising', emphasis: false },
    { key: 'marketReturn', label: 'Market return', emphasis: false },
    { key: 'totalIncome', label: 'Total income', emphasis: true },
    { key: 'awardCosts', label: 'Award costs', emphasis: false },
    { key: 'opExpenses', label: 'Operating expenses', emphasis: false },
    { key: 'totalExpenses', label: 'Total expenses', emphasis: true },
    { key: 'totalPL', label: 'Total P&L', emphasis: false },
    { key: 'beginningEndowment', label: 'FY beginning endowment', emphasis: false },
    { key: 'endingEndowment', label: 'FY ending endowment', emphasis: true },
  ] as const;

  return (
    <div className="space-y-6">
      <section className="card">
        <div className="card-header flex items-center justify-between">
          <div>
            <div className="eyebrow">Endowment trajectory</div>
            <h2 className="font-head text-base">FY15 historical · FY27–FY35 projection</h2>
          </div>
        </div>
        <div className="card-body">
          <div className="h-[360px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 10, right: 24, bottom: 8, left: 0 }}>
                <CartesianGrid strokeDasharray="2 4" stroke="#101A4C20" />
                <XAxis
                  dataKey="fiscalYear"
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(fy) => fyLabel(Number(fy))}
                  stroke="#101A4C40"
                />
                <YAxis
                  tick={{ fill: '#101A4C', fontSize: 12 }}
                  tickFormatter={(v) => `$${(v / 1_000_000).toFixed(0)}M`}
                  stroke="#101A4C40"
                  width={64}
                />
                <Tooltip
                  contentStyle={{
                    background: 'white',
                    border: '1px solid #101A4C20',
                    borderRadius: 8,
                    fontFamily: 'Noto Serif, serif',
                  }}
                  formatter={(v) => millions(Number(v))}
                  labelFormatter={(fy) => `FY${String(fy).slice(-2)}`}
                />
                <Legend wrapperStyle={{ paddingTop: 8 }} />
                <Line
                  type="monotone"
                  dataKey="Historical"
                  stroke={SCENARIO_COLORS.Historical}
                  strokeWidth={2.5}
                  dot={false}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Base"
                  stroke={SCENARIO_COLORS.Base}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Optimistic"
                  stroke={SCENARIO_COLORS.Optimistic}
                  strokeWidth={2.5}
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
                <Line
                  type="monotone"
                  dataKey="Pessimistic"
                  stroke={SCENARIO_COLORS.Pessimistic}
                  strokeWidth={2.5}
                  strokeDasharray="6 4"
                  dot={{ r: 3 }}
                  connectNulls={false}
                />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </section>

      <section className="card">
        <div className="card-header flex items-center justify-between">
          <div>
            <div className="eyebrow">Financial overview</div>
            <h2 className="font-head text-base">{scenario} scenario · FY27 – FY35</h2>
          </div>
          <div className="flex items-center gap-2">
            {(['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) => (
              <button
                key={s}
                onClick={() => setScenario(s)}
                className={`tab-btn ${scenario === s ? 'tab-btn-active' : ''}`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
        <div className="card-body overflow-x-auto">
          <table className="w-full text-sm num">
            <thead>
              <tr className="text-navy/60 uppercase text-xs tracking-wider">
                <th className="text-left py-2 pr-4 font-semibold">Financial metric</th>
                {active.years.map((y) => (
                  <th key={y.fiscalYear} className="text-right px-3 py-2 font-semibold">
                    {fyLabel(y.fiscalYear)}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rowDefs.map((row) => (
                <tr
                  key={row.key}
                  className={
                    row.emphasis
                      ? 'bg-tan/60 border-y-2 border-navy/80 font-semibold'
                      : 'border-b border-navy/5'
                  }
                >
                  <td className="text-left py-2 pr-4 text-navy">{row.label}</td>
                  {active.years.map((y) => (
                    <td key={y.fiscalYear} className="text-right px-3 py-2 text-navy">
                      {dollars((y as never)[row.key] as number)}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div className="card-body border-t border-navy/10 text-xs text-navy/70 font-sub">
          <p className="font-semibold mb-1 text-navy">Key assumptions</p>
          <ul className="list-disc list-inside space-y-0.5">
            <li>Award costs step down: $5.4M FY27 → $4.5M FY28 → $4.0M FY29, settling $4.0–4.3M.</li>
            <li>Operating expenses grow 1.5%/year with a one-time $500K reduction in FY29 (lease end).</li>
            <li>FY26 ending endowment of $100M reflects major gift, fundraising, and market growth.</li>
            <li>All projections subject to market conditions and successful execution of cost plan.</li>
          </ul>
        </div>
      </section>
    </div>
  );
}
