import { useState } from 'react';
import type { FinancialInputs, ScenarioName } from '../lib/model';
import { fiscalYears } from '../lib/model';
import { fyLabel } from '../lib/format';

interface InputsPanelProps {
  inputs: FinancialInputs;
  setInputs: (next: FinancialInputs) => void;
}

type SubTab = 'financial' | 'market';

export function InputsPanel({ inputs, setInputs }: InputsPanelProps) {
  const [tab, setTab] = useState<SubTab>('financial');
  const years = fiscalYears();

  const updateArr = (
    key: 'awardCosts' | 'fundraising',
    idx: number,
    valueDollars: number
  ) => {
    const next = [...inputs[key]];
    next[idx] = valueDollars;
    setInputs({ ...inputs, [key]: next });
  };

  const updateMarket = (scenario: ScenarioName, idx: number, valuePct: number) => {
    const arr = [...inputs.marketReturn[scenario]];
    arr[idx] = valuePct;
    setInputs({
      ...inputs,
      marketReturn: { ...inputs.marketReturn, [scenario]: arr },
    });
  };

  return (
    <aside className="card sticky top-4">
      <div className="card-header flex items-center justify-between">
        <span className="font-head uppercase tracking-wide-15 text-sm">Forecast Parameters</span>
      </div>
      <div className="px-3 pt-3">
        <div className="flex gap-1 bg-tan rounded-lg p-1">
          <button
            className={`tab-btn flex-1 ${tab === 'financial' ? 'tab-btn-active' : ''}`}
            onClick={() => setTab('financial')}
          >
            Financial
          </button>
          <button
            className={`tab-btn flex-1 ${tab === 'market' ? 'tab-btn-active' : ''}`}
            onClick={() => setTab('market')}
          >
            Market
          </button>
        </div>
      </div>

      <div className="card-body max-h-[calc(100vh-13rem)] overflow-y-auto">
        {tab === 'financial' && (
          <div className="space-y-5">
            <div>
              <div className="eyebrow mb-1">Endowment</div>
              <div className="input-row">
                <label className="label">FY27 beginning ($M)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={(inputs.beginningEndowment / 1_000_000).toFixed(1)}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      beginningEndowment: Number(e.target.value) * 1_000_000,
                    })
                  }
                />
              </div>
            </div>

            <div>
              <div className="eyebrow mb-1">Fundraising target by year ($M)</div>
              {years.map((fy, i) => (
                <div key={fy} className="input-row">
                  <label className="label">{fyLabel(fy)}</label>
                  <input
                    type="number"
                    step="0.1"
                    className="input-num"
                    value={(inputs.fundraising[i] / 1_000_000).toFixed(1)}
                    onChange={(e) =>
                      updateArr('fundraising', i, Number(e.target.value) * 1_000_000)
                    }
                  />
                </div>
              ))}
            </div>

            <div>
              <div className="eyebrow mb-1">Award costs by year ($M)</div>
              {years.map((fy, i) => (
                <div key={fy} className="input-row">
                  <label className="label">{fyLabel(fy)}</label>
                  <input
                    type="number"
                    step="0.1"
                    className="input-num"
                    value={(inputs.awardCosts[i] / 1_000_000).toFixed(1)}
                    onChange={(e) =>
                      updateArr('awardCosts', i, Number(e.target.value) * 1_000_000)
                    }
                  />
                </div>
              ))}
            </div>

            <div>
              <div className="eyebrow mb-1">Operating expenses</div>
              <div className="input-row">
                <label className="label">FY27 init ($M)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={(inputs.opExpensesInit / 1_000_000).toFixed(1)}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      opExpensesInit: Number(e.target.value) * 1_000_000,
                    })
                  }
                />
              </div>
              <div className="input-row">
                <label className="label">Annual growth (%)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={inputs.opExpensesGrowth}
                  onChange={(e) =>
                    setInputs({ ...inputs, opExpensesGrowth: Number(e.target.value) })
                  }
                />
              </div>
              <div className="input-row">
                <label className="label">One-time reduction year</label>
                <input
                  type="number"
                  step="1"
                  className="input-num"
                  value={inputs.opExpensesReductionYear}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      opExpensesReductionYear: Number(e.target.value),
                    })
                  }
                />
              </div>
              <div className="input-row">
                <label className="label">Reduction amount ($M)</label>
                <input
                  type="number"
                  step="0.1"
                  className="input-num"
                  value={(inputs.opExpensesReductionAmount / 1_000_000).toFixed(2)}
                  onChange={(e) =>
                    setInputs({
                      ...inputs,
                      opExpensesReductionAmount: Number(e.target.value) * 1_000_000,
                    })
                  }
                />
              </div>
            </div>
          </div>
        )}

        {tab === 'market' && (
          <div className="space-y-5">
            {(['Base', 'Optimistic', 'Pessimistic'] as ScenarioName[]).map((s) => (
              <div key={s}>
                <div className="eyebrow mb-1">{s} scenario — return %</div>
                {years.map((fy, i) => (
                  <div key={fy} className="input-row">
                    <label className="label">{fyLabel(fy)}</label>
                    <input
                      type="number"
                      step="0.1"
                      className="input-num"
                      value={inputs.marketReturn[s][i]}
                      onChange={(e) => updateMarket(s, i, Number(e.target.value))}
                    />
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}
      </div>
    </aside>
  );
}
