// Monte Carlo simulation: market-return uncertainty applied to the financial model.

import type { FinancialInputs } from './model';
import { fiscalYears, opExpensesAtYear } from './model';

export interface MonteCarloResult {
  /** Per-year percentile endowment paths (10th, 50th, 90th). */
  bands: { fiscalYear: number; p10: number; p50: number; p90: number }[];
  /** FY35 ending endowment distribution — sorted ascending for downstream histogram/quantiles. */
  endingDistribution: number[];
  /** Probability that ending endowment by FY35 stays above the floor. */
  probAboveFloor: number;
  /** Probability that ending endowment goes negative at any point. */
  probInsolvent: number;
  /** Mean and std-dev used for sampling, for display. */
  meanReturn: number;
  stdReturn: number;
  trials: number;
}

/** Box–Muller transform — returns one standard normal draw. */
function randn(): number {
  let u = 0;
  let v = 0;
  while (u === 0) u = Math.random();
  while (v === 0) v = Math.random();
  return Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
}

export interface MonteCarloOptions {
  /** Mean annual return, percent. */
  meanReturn: number;
  /** Std-dev of annual return, percent. */
  stdReturn: number;
  /** Number of simulations. */
  trials: number;
  /** Endowment floor for "probability above floor" calculation. */
  floor: number;
  /** Optional seed for reproducibility (skipped for now — Math.random doesn't support seeds natively). */
}

export function runMonteCarlo(
  inputs: FinancialInputs,
  opts: MonteCarloOptions
): MonteCarloResult {
  const years = fiscalYears();
  const N = opts.trials;
  const T = years.length;

  // Pre-compute deterministic per-year expenses & fundraising
  const fundraising = inputs.fundraising;
  const awardCosts = inputs.awardCosts;
  const opExpenses = years.map((_, i) =>
    opExpensesAtYear(
      i,
      inputs.opExpensesInit,
      inputs.opExpensesGrowth,
      inputs.opExpensesReductionYear,
      inputs.opExpensesReductionAmount
    )
  );
  const totalExpenses = opExpenses.map((op, i) => op + (awardCosts[i] ?? 0));

  // Trials × Years matrix of ending endowments
  const paths: number[][] = Array.from({ length: T }, () => new Array(N).fill(0));
  const endingByTrial: number[] = new Array(N);
  let insolventCount = 0;

  for (let trial = 0; trial < N; trial++) {
    let beg = inputs.beginningEndowment;
    let wentNegative = false;
    for (let i = 0; i < T; i++) {
      // Draw return from N(meanReturn, stdReturn)
      const ret = opts.meanReturn + opts.stdReturn * randn();
      const market = beg * (ret / 100);
      const income = (fundraising[i] ?? 0) + market;
      const ending = beg + income - totalExpenses[i];
      if (ending < 0) wentNegative = true;
      paths[i][trial] = ending;
      beg = ending;
    }
    endingByTrial[trial] = paths[T - 1][trial];
    if (wentNegative) insolventCount++;
  }

  // Sort each year's slice for percentile lookup
  const bands = years.map((fy, i) => {
    const slice = [...paths[i]].sort((a, b) => a - b);
    return {
      fiscalYear: fy,
      p10: slice[Math.floor(N * 0.1)],
      p50: slice[Math.floor(N * 0.5)],
      p90: slice[Math.floor(N * 0.9)],
    };
  });

  const sortedEnding = [...endingByTrial].sort((a, b) => a - b);
  const aboveFloorCount = endingByTrial.filter((v) => v >= opts.floor).length;

  return {
    bands,
    endingDistribution: sortedEnding,
    probAboveFloor: aboveFloorCount / N,
    probInsolvent: insolventCount / N,
    meanReturn: opts.meanReturn,
    stdReturn: opts.stdReturn,
    trials: N,
  };
}
