// DC CAP financial model — FY27 baseline.
// Pure functions. No DOM, no React. Fully unit-testable.
//
// Window: FY27 → FY35 (9 years). Historical chart context: FY15 → FY26.
// All monetary values are stored in dollars (not millions). UI converts at the boundary.

export type ScenarioName = 'Base' | 'Optimistic' | 'Pessimistic';

export interface PhilanthropicYear {
  /** Locked, signed gifts and pledges already counted as revenue. */
  committed: number;
  /** Reasonable likelihood — renewals from existing donors, late-stage proposals. */
  likely: number;
  /** Unfilled portion of the fundraising target. The "to-find" closing problem. */
  gap: number;
}

export interface FinancialInputs {
  /** Beginning endowment for the first year of the projection window (FY27). */
  beginningEndowment: number;
  /** Award costs target by year (FY27 → FY35), in dollars. */
  awardCosts: number[];
  /** Operating expense target for FY27 (subsequent years grow at opExpensesGrowth). */
  opExpensesInit: number;
  /** Annual operating expense growth rate, percent (e.g., 1.5 means 1.5%). */
  opExpensesGrowth: number;
  /** One-time op-expense reduction year (1-indexed). FY27=1, FY28=2, FY29=3, etc. */
  opExpensesReductionYear: number;
  /** One-time op-expense reduction amount, in dollars. */
  opExpensesReductionAmount: number;
  /** Total fundraising target by year (FY27 → FY35), in dollars. */
  fundraising: number[];
  /** Per-year philanthropic decomposition. Length matches projection window. */
  philanthropic: PhilanthropicYear[];
  /** Annual market return assumptions per scenario, percent. Length matches window. */
  marketReturn: Record<ScenarioName, number[]>;
}

export interface YearMetrics {
  fiscalYear: number;
  beginningEndowment: number;
  fundraising: number;
  marketReturn: number;
  totalIncome: number;
  awardCosts: number;
  opExpenses: number;
  totalExpenses: number;
  totalPL: number;
  endingEndowment: number;
  /**
   * Net draw on the endowment as a fraction of beginning endowment.
   * Defined as (totalExpenses − fundraising) / beginningEndowment.
   * This is the standard endowment-policy benchmark (4.5% sustainable, etc.) —
   * fundraising offsets operating costs before any draw on the endowment.
   * Negative values mean the year was a net contributor to the endowment (good).
   */
  spendRate: number;
}

export interface ScenarioProjection {
  scenario: ScenarioName;
  years: YearMetrics[];
}

